+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        engine: Engine,
+        harness_loader: *harness.HarnessLoader,
+        timeout_ms: u32,
+    ) Runner {
+        return .{
+            .allocator = allocator,
+            .engine = engine,
+            .harness_loader = harness_loader,
+            .timeout_ms = timeout_ms,
+            .temp_dir = "/tmp/test262",
+            .temp_counter = 0,
