+        var stdout_buf: std.ArrayListUnmanaged(u8) = .{};
+        defer stdout_buf.deinit(self.allocator);
+        var stderr_buf: std.ArrayListUnmanaged(u8) = .{};
+        defer stderr_buf.deinit(self.allocator);
