+        if (result.exit_code == 0) {
+            // Check for async test failure marker
+            if (result.stdout) |stdout| {
+                if (std.mem.indexOf(u8, stdout, "Test262:AsyncTestFailure") != null) {
+                    return .fail;
+                }
+            }
+            return .pass;
+        }
+
+        return .fail;
+    }
+};

